func (backRepoCylinderGeometry *BackRepoCylinderGeometryStruct) RestoreXLPhaseOne(file *xlsx.File) {

	// resets the map
	BackRepoCylinderGeometryid_atBckpTime_newID = make(map[uint]uint)

	sh, ok := file.Sheet["CylinderGeometry"]
	_ = sh
	if !ok {
		log.Fatal(errors.New("sheet not found"))
	}

	// log.Println("Max row is", sh.MaxRow)
	err := sh.ForEachRow(backRepoCylinderGeometry.rowVisitorCylinderGeometry)
	if err != nil {
		log.Fatal("Err=", err)
	}
}

func (backRepoCylinderGeometry *BackRepoCylinderGeometryStruct) rowVisitorCylinderGeometry(row *xlsx.Row) error {

	log.Printf("row line %d\n", row.GetCoordinate())
	log.Println(row)

	// skip first line
	if row.GetCoordinate() > 0 {
		var cylindergeometryWOP CylinderGeometryWOP
		row.ReadStruct(&cylindergeometryWOP)

		// add the unmarshalled struct to the stage
		cylindergeometryDB := new(CylinderGeometryDB)
		cylindergeometryDB.CopyBasicFieldsFromCylinderGeometryWOP(&cylindergeometryWOP)

		cylindergeometryDB_ID_atBackupTime := cylindergeometryDB.ID
		cylindergeometryDB.ID = 0
		_, err := backRepoCylinderGeometry.db.Create(cylindergeometryDB)
		if err != nil {
			log.Fatal(err)
		}
		backRepoCylinderGeometry.Map_CylinderGeometryDBID_CylinderGeometryDB[cylindergeometryDB.ID] = cylindergeometryDB
		BackRepoCylinderGeometryid_atBckpTime_newID[cylindergeometryDB_ID_atBackupTime] = cylindergeometryDB.ID
	}
	return nil
}

// RestorePhaseOne read the file "CylinderGeometryDB.json" in dirPath that stores an array
// of CylinderGeometryDB and stores it in the database
// the map BackRepoCylinderGeometryid_atBckpTime_newID is updated accordingly
func (backRepoCylinderGeometry *BackRepoCylinderGeometryStruct) RestorePhaseOne(dirPath string) {

	// resets the map
	BackRepoCylinderGeometryid_atBckpTime_newID = make(map[uint]uint)

	filename := filepath.Join(dirPath, "CylinderGeometryDB.json")
	jsonFile, err := os.Open(filename)
	// if we os.Open returns an error then handle it
	if err != nil {
		log.Fatal("Cannot restore/open the json CylinderGeometry file", filename, " ", err.Error())
	}

	// read our opened jsonFile as a byte array.
	byteValue, _ := ioutil.ReadAll(jsonFile)

	var forRestore []*CylinderGeometryDB

	err = json.Unmarshal(byteValue, &forRestore)

	// fill up Map_CylinderGeometryDBID_CylinderGeometryDB
	for _, cylindergeometryDB := range forRestore {

		cylindergeometryDB_ID_atBackupTime := cylindergeometryDB.ID
		cylindergeometryDB.ID = 0
		_, err := backRepoCylinderGeometry.db.Create(cylindergeometryDB)
		if err != nil {
			log.Fatal(err)
		}
		backRepoCylinderGeometry.Map_CylinderGeometryDBID_CylinderGeometryDB[cylindergeometryDB.ID] = cylindergeometryDB
		BackRepoCylinderGeometryid_atBckpTime_newID[cylindergeometryDB_ID_atBackupTime] = cylindergeometryDB.ID
	}

	if err != nil {
		log.Fatal("Cannot restore/unmarshall json CylinderGeometry file", err.Error())
	}
}

// RestorePhaseTwo uses all map BackRepo<CylinderGeometry>id_atBckpTime_newID
// to compute new index
func (backRepoCylinderGeometry *BackRepoCylinderGeometryStruct) RestorePhaseTwo() {

	for _, cylindergeometryDB := range backRepoCylinderGeometry.Map_CylinderGeometryDBID_CylinderGeometryDB {

		// next line of code is to avert unused variable compilation error
		_ = cylindergeometryDB

		// insertion point for reindexing pointers encoding
		// update databse with new index encoding
		db, _ := backRepoCylinderGeometry.db.Model(cylindergeometryDB)
		_, err := db.Updates(*cylindergeometryDB)
		if err != nil {
			log.Fatal(err)
		}
	}

}

